/**
 * Bounded high-yield nursing glossary (MVP). Expand via editorial review — not autogenerated spam.
 */

export type NursingGlossaryTerm = {
  slug: string;
  term: string;
  definition: string;
  /** Canonical topic slug for lesson/question cross-links */
  topicSlug: string;
  relatedTermSlugs?: readonly string[];
};

