export function getNursingGlossaryTerm(slug: string): NursingGlossaryTerm | undefined {
  const key = slug.trim().toLowerCase();
  return NURSING_GLOSSARY_TERMS.find((t) => t.slug === key);
}

export function listNursingGlossaryTerms(): NursingGlossaryTerm[] {
  return [...NURSING_GLOSSARY_TERMS];
}
